// Hook to determine if we should use lightweight mode for better performance
const useLightweightMode = (): boolean => {
  // Safely access window properties with fallbacks for SSR/restricted environments
  const getWindowWidth = () => {
    try {
      return typeof window !== 'undefined' ? window.innerWidth : 1024;
    } catch {
      return 1024;
    }
  };
  
  const getConnection = () => {
    try {
      return typeof navigator !== 'undefined' ? (navigator as any).connection : null;
    } catch {
      return null;
    }
  };
  
  const getDeviceMemory = () => {
    try {
      return typeof navigator !== 'undefined' ? (navigator as any).deviceMemory : null;
    } catch {
      return null;
    }
  };

  const windowWidth = getWindowWidth();
  const isMobile = windowWidth < 640;
  const isDesktop = windowWidth >= 1024;
  const connection = getConnection();
  
  // Detection for iOS environments - wrapped in try-catch for safety
  let isCapacitor = false;
  let isWebView = false;
  
  try {
    isCapacitor = isCapacitorApp();
    isWebView = isInWebView();
  } catch (e) {
    console.warn('[useLightweightMode] Environment detection failed:', e);
  }
  
  // Desktop: only use lightweight mode if user explicitly enabled data saver
  if (isDesktop) {
    if (connection?.saveData) return true;
    return false; // Desktop always loads video by default
  }
  
  // Mobile/Tablet: WebView environments use lightweight mode
  // But exclude Capacitor native apps (user's own app should play videos)
  if (isWebView && !isCapacitor) {
    return true;
  }
  
  // Check for slow network or data saver (mobile/tablet)
  if (connection) {
    if (connection.saveData) return true;
    if (connection.effectiveType === '2g' || connection.effectiveType === 'slow-2g') return true;
  }
  
  // Mobile low memory devices (< 2GB) - reduced threshold
  const deviceMemory = getDeviceMemory();
  if (isMobile && deviceMemory && deviceMemory < 2) return true;
  
  return false;
};

// Hero Slide Component
const HeroSlide = memo(({ 
  template, 
  isActive, 
  currentLang, 
  t,
  onContentReady,
  onAskXiaoxiong,
  onDIYCook,
  onPhotoStory
}: { 
  template: HomepageTemplate; 
  isActive: boolean;
  currentLang: string;
  t: any;
  onContentReady?: () => void;
  onAskXiaoxiong?: () => void;
  onDIYCook?: () => void;
  onPhotoStory?: (storyText: string, templateId: string) => void;
}) => {
  const [postersLoaded, setPostersLoaded] = useState<Record<string, boolean>>({});
  const [videosReady, setVideosReady] = useState<Record<string, boolean>>({});
  const [videoErrors, setVideoErrors] = useState<Record<string, boolean>>({});
  const [imagesLoaded, setImagesLoaded] = useState<Record<string, boolean>>({
    mobile: true,
    tablet: true, 
    desktop: true
  });
  // Control when to start loading videos - only after image is ready
  const [shouldLoadVideo, setShouldLoadVideo] = useState(false);
  const isLightweight = useLightweightMode();
  
  // Video refs for iOS Safari fix
  const mobileVideoRef = useRef<HTMLVideoElement>(null);
  const tabletVideoRef = useRef<HTMLVideoElement>(null);
  const desktopVideoRef = useRef<HTMLVideoElement>(null);
  
  const getLocalizedText = (field: string) => {
    // Only use DB columns for languages that have dedicated columns (zh, pt, en)
    // For other languages, return empty to allow t() fallback
    const langSuffix = currentLang === "zh" ? "_zh" : currentLang === "pt" ? "_pt" : currentLang === "en" ? "_en" : null;
    if (!langSuffix) return "";
    return (template as any)[`${field}${langSuffix}`] || "";
  };

  const getDeviceType = () => {
    try {
      if (typeof window === 'undefined') return 'desktop';
      const width = window.innerWidth;
      if (width < 640) return 'mobile';
      if (width < 1024) return 'tablet';
      return 'desktop';
    } catch {
      return 'desktop';
    }
  };

  const getOverlayOpacity = () => {
    const deviceType = getDeviceType();
    
    if (deviceType === 'mobile' && template.mobile_overlay_opacity !== null) {
      return template.mobile_overlay_opacity;
    }
    if (deviceType === 'tablet' && template.tablet_overlay_opacity !== null) {
      return template.tablet_overlay_opacity;
    }
    if (deviceType === 'desktop' && template.desktop_overlay_opacity !== null) {
      return template.desktop_overlay_opacity;
    }
    
    return template.overlay_opacity ?? 30;
  };

  const getOverlayStyle = () => {
    const baseOpacity = getOverlayOpacity();
    const direction = template.overlay_gradient_direction || 'to-b';
    
    const normalizeOpacity = (value: number | null | undefined, defaultValue: number) => {
      if (value === null || value === undefined) return defaultValue / 100;
      return value > 1 ? value / 100 : value;
    };
    
    const normalizedBaseOpacity = baseOpacity > 1 ? baseOpacity / 100 : baseOpacity;
    
    const fromOpacity = normalizeOpacity(template.overlay_gradient_from_opacity, 30) * normalizedBaseOpacity;
    const viaOpacity = normalizeOpacity(template.overlay_gradient_via_opacity, 25) * normalizedBaseOpacity;
    const toOpacity = normalizeOpacity(template.overlay_gradient_to_opacity, 40) * normalizedBaseOpacity;

    const directionMap: Record<string, string> = {
      'to-t': 'to top',
      'to-b': 'to bottom',
      'to-l': 'to left',
      'to-r': 'to right',
      'to-tl': 'to top left',
      'to-tr': 'to top right',
      'to-bl': 'to bottom left',
      'to-br': 'to bottom right'
    };

    const cssDirection = directionMap[direction] || 'to bottom';

    const colorMap: Record<string, string> = {
      'black': '0, 0, 0',
      'white': '255, 255, 255',
      'background': '0, 0, 0',
      'foreground': '255, 255, 255',
      'primary': '1, 100, 80',
      'secondary': '240, 240, 240'
    };

    const fromColor = colorMap[template.overlay_gradient_from || 'black'] || '0, 0, 0';
    const viaColor = colorMap[template.overlay_gradient_via || 'black'] || '0, 0, 0';
    const toColor = colorMap[template.overlay_gradient_to || 'black'] || '0, 0, 0';

    return {
      background: `linear-gradient(${cssDirection}, rgba(${fromColor}, ${fromOpacity}), rgba(${viaColor}, ${viaOpacity}), rgba(${toColor}, ${toOpacity}))`
    };
  };

  const mobileImg = template.mobile_image_url || sushiRamenMobile;
  const tabletImg = template.tablet_image_url || template.desktop_image_url || sushiRamenHero;
  const desktopImg = template.desktop_image_url || sushiRamenHero;
  const blurAmount = template.background_blur || 0;

  // Per-device media type (fallback to global media_type for backwards compatibility)
  const desktopMediaType = (template as any).desktop_media_type || template.media_type || 'image';
  const tabletMediaType = (template as any).tablet_media_type || template.media_type || 'image';
  const mobileMediaType = (template as any).mobile_media_type || template.media_type || 'image';

  // In lightweight mode (WebView), always treat as image to avoid video loading overhead
  const isDesktopVideo = desktopMediaType === 'video' && !isLightweight;
  const isTabletVideo = tabletMediaType === 'video' && !isLightweight;
  const isMobileVideo = mobileMediaType === 'video' && !isLightweight;
  
  const mobileVideo = isMobileVideo ? template.mobile_video_url : null;
  const tabletVideo = isTabletVideo ? (template.tablet_video_url || template.desktop_video_url) : null;
  const desktopVideo = isDesktopVideo ? template.desktop_video_url : null;

  // Preload only current device's poster image to prevent flash
  useEffect(() => {
    const deviceType = getDeviceType();
    const currentImage = deviceType === 'mobile' ? mobileImg 
      : deviceType === 'tablet' ? tabletImg : desktopImg;
    
    if (currentImage) {
      const img = new Image();
      img.onload = () => {
        setPostersLoaded(prev => ({ ...prev, [deviceType]: true }));
        setImagesLoaded(prev => ({ ...prev, [deviceType]: true }));
        // Image is ready - notify parent and start loading video
        if (isActive) {
          onContentReady?.();
          // Start loading video after image is displayed (with slight delay for smoother UX)
          setTimeout(() => setShouldLoadVideo(true), 100);
        }
      };
      img.src = currentImage;
    }
  }, [mobileImg, tabletImg, desktopImg, isActive, onContentReady]);

  // Also enable video loading when slide becomes active (for carousel navigation)
  useEffect(() => {
    if (isActive && postersLoaded[getDeviceType()]) {
      setShouldLoadVideo(true);
    }
  }, [isActive, postersLoaded]);

  const handleVideoCanPlay = (device: string) => {
    setVideosReady(prev => ({ ...prev, [device]: true }));
  };

  const handleVideoError = (device: string, error: any) => {
    console.error(`[HeroSlide] Video error on ${device}:`, error);
    setVideoErrors(prev => ({ ...prev, [device]: true }));
  };

  // iOS Safari video autoplay fix - programmatically set muted and trigger play
  useEffect(() => {
    if (!shouldLoadVideo || !isActive) return;
    
    let isIOS = false;
    try {
      isIOS = isIOSDevice();
    } catch {
      // Ignore detection errors in restricted WebView environments
    }
    if (!isIOS) return;

    const deviceType = getDeviceType();
    const videoRef = deviceType === 'mobile' ? mobileVideoRef 
      : deviceType === 'tablet' ? tabletVideoRef : desktopVideoRef;
    
    const video = videoRef.current;
    if (!video) return;

    // For iOS, we need to programmatically ensure muted is set and call play()
    const attemptPlay = async () => {
      try {
        video.muted = true;
        video.playsInline = true;
        // Set webkit-playsinline for older iOS versions
        video.setAttribute('webkit-playsinline', 'true');
        
        await video.play();
        console.log(`[HeroSlide] iOS video play successful on ${deviceType}`);
      } catch (err) {
        console.error(`[HeroSlide] iOS video play failed on ${deviceType}:`, err);
        // Mark as error so we show the fallback image
        setVideoErrors(prev => ({ ...prev, [deviceType]: true }));
      }
    };

    // Small delay to ensure video element is ready
    const timer = setTimeout(attemptPlay, 150);
    return () => clearTimeout(timer);
  }, [shouldLoadVideo, isActive]);

  return (
    <div className={cn(
      "absolute inset-0 w-full h-full transition-opacity duration-1000",
      isActive ? "opacity-100 z-10" : "opacity-0 z-0"
    )}>
      {/* 背景媒体 */}
      <div className="absolute inset-0 w-full h-full">
        {/* Mobile: Per-device media type */}
        <div className="absolute inset-0 w-full h-full sm:hidden">
          {!imagesLoaded.mobile && (
            <div className="absolute inset-0 w-full h-full bg-muted animate-pulse z-20" />
          )}
          {isMobileVideo && mobileVideo ? (
            <>
              <img 
                src={mobileImg} 
                alt="Background" 
                className={cn(
                  "absolute inset-0 w-full h-full object-cover object-center z-10 transition-opacity duration-500",
                  videosReady.mobile && !videoErrors.mobile ? "opacity-0 pointer-events-none" : "opacity-100"
                )}
                style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
              />
              {shouldLoadVideo && !videoErrors.mobile && (
                <video
                  ref={mobileVideoRef}
                  src={mobileVideo}
                  autoPlay
                  loop
                  muted
                  playsInline
                  // @ts-ignore - webkit-playsinline for iOS Safari
                  webkit-playsinline="true"
                  preload="auto"
                  onCanPlay={() => handleVideoCanPlay('mobile')}
                  onError={(e) => handleVideoError('mobile', e)}
                  className="absolute inset-0 w-full h-full object-cover object-center"
                  style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
                />
              )}
            </>
          ) : (
            <img 
              src={mobileImg} 
              alt="Background" 
              className={cn(
                "absolute inset-0 w-full h-full object-cover object-center transition-opacity duration-500",
                imagesLoaded.mobile ? "opacity-100" : "opacity-0"
              )}
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          )}
        </div>
        
        {/* Tablet: Per-device media type */}
        <div className="absolute inset-0 w-full h-full hidden sm:block lg:hidden">
          {!imagesLoaded.tablet && (
            <div className="absolute inset-0 w-full h-full bg-muted animate-pulse z-20" />
          )}
          {isTabletVideo && tabletVideo ? (
            <>
              <img 
                src={tabletImg} 
                alt="Background" 
                className={cn(
                  "absolute inset-0 w-full h-full object-cover object-center z-10 transition-opacity duration-500",
                  videosReady.tablet && !videoErrors.tablet ? "opacity-0 pointer-events-none" : "opacity-100"
                )}
                style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
              />
              {shouldLoadVideo && !videoErrors.tablet && (
                <video
                  ref={tabletVideoRef}
                  src={tabletVideo}
                  autoPlay
                  loop
                  muted
                  playsInline
                  // @ts-ignore - webkit-playsinline for iOS Safari
                  webkit-playsinline="true"
                  preload="auto"
                  onCanPlay={() => handleVideoCanPlay('tablet')}
                  onError={(e) => handleVideoError('tablet', e)}
                  className="absolute inset-0 w-full h-full object-cover object-center"
                  style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
                />
              )}
            </>
          ) : (
            <img 
              src={tabletImg} 
              alt="Background" 
              className={cn(
                "absolute inset-0 w-full h-full object-cover object-center transition-opacity duration-500",
                imagesLoaded.tablet ? "opacity-100" : "opacity-0"
              )}
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          )}
        </div>
        
        {/* Desktop: Per-device media type */}
        <div className="absolute inset-0 w-full h-full hidden lg:block">
          {!imagesLoaded.desktop && (
            <div className="absolute inset-0 w-full h-full bg-muted animate-pulse z-20" />
          )}
          {isDesktopVideo && desktopVideo ? (
            <>
              <img 
                src={desktopImg} 
                alt="Background" 
                className={cn(
                  "absolute inset-0 w-full h-full object-cover object-center z-10 transition-opacity duration-500",
                  videosReady.desktop && !videoErrors.desktop ? "opacity-0 pointer-events-none" : "opacity-100"
                )}
                style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
              />
              {shouldLoadVideo && !videoErrors.desktop && (
                <video
                  ref={desktopVideoRef}
                  src={desktopVideo}
                  autoPlay
                  loop
                  muted
                  playsInline
                  // @ts-ignore - webkit-playsinline for iOS Safari
                  webkit-playsinline="true"
                  preload="auto"
                  onCanPlay={() => handleVideoCanPlay('desktop')}
                  onError={(e) => handleVideoError('desktop', e)}
                  className="absolute inset-0 w-full h-full object-cover object-center"
                  style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
                />
              )}
            </>
          ) : (
            <img 
              src={desktopImg} 
              alt="Background" 
              fetchPriority="high"
              loading="eager"
              decoding="async"
              className={cn(
                "absolute inset-0 w-full h-full object-cover object-center transition-opacity duration-500",
                imagesLoaded.desktop ? "opacity-100" : "opacity-0"
              )}
              style={{ filter: blurAmount > 0 ? `blur(${blurAmount}px)` : undefined }}
            />
          )}
        </div>
        <div className="absolute inset-0 w-full h-full" style={getOverlayStyle()} />
      </div>

      {/* 内容 */}
      <div className="relative z-10 container mx-auto px-4 sm:px-6 flex items-center justify-center min-h-screen">
        <div className="max-w-4xl mx-auto text-center space-y-4 sm:space-y-8 animate-fade-in w-full">
          <h1 className="text-3xl sm:text-5xl md:text-7xl font-bold text-white leading-tight px-4 drop-shadow-[0_2px_8px_rgba(0,0,0,0.8)]">
            {getLocalizedText("title") || t("home.hero.title")}
          </h1>
          
          <p className="text-sm sm:text-xl md:text-2xl text-white/95 max-w-2xl mx-auto px-4 drop-shadow-[0_2px_6px_rgba(0,0,0,0.7)]">
            {getLocalizedText("description") || t("home.hero.description")}
          </p>
          
          {template.subtitle_button_text_zh && (
            <div className="flex flex-col items-center gap-3">
              <button 
                onClick={onAskXiaoxiong}
                className="group flex items-center gap-3 bg-white/20 backdrop-blur-xl text-white px-5 sm:px-7 py-3.5 sm:py-4 rounded-full shadow-[0_8px_32px_rgba(0,0,0,0.12)] hover:shadow-[0_16px_48px_rgba(0,0,0,0.2)] hover:bg-white/30 transition-all duration-300 cursor-text border border-white/40"
              >
                <MessageCircle className="w-5 h-5 text-white/90 group-hover:text-white transition-colors drop-shadow-sm" />
                <span className="text-sm sm:text-base text-white group-hover:text-white/80 transition-colors drop-shadow-sm font-medium">
                  {getLocalizedText("subtitle_button_text") || t("home.hero.subtitle")}
                </span>
                <Search className="w-4 h-4 text-white/60 ml-2 drop-shadow-sm" />
              </button>

              {/* Divider */}
              <div className="flex items-center gap-3 w-64">
                <div className="flex-1 h-px bg-white/30" />
                <span className="text-xs text-white/60">{t("aiRecipe.or", "或者")}</span>
                <div className="flex-1 h-px bg-white/30" />
              </div>

              {/* DIY Cook Button */}
              <button 
                onClick={onDIYCook}
                className="group flex items-center gap-3 bg-white/20 backdrop-blur-xl text-white px-5 sm:px-7 py-3.5 sm:py-4 rounded-full shadow-[0_8px_32px_rgba(0,0,0,0.12)] hover:shadow-[0_16px_48px_rgba(0,0,0,0.2)] hover:bg-white/30 transition-all duration-300 border border-white/40"
              >
                <ChefHat className="w-5 h-5 text-white/90 group-hover:text-white transition-colors drop-shadow-sm" />
                <span className="text-sm sm:text-base text-white group-hover:text-white/80 transition-colors drop-shadow-sm font-medium">
                  {t("aiRecipe.diyCook", "自己动手做")}
                </span>
                <BookOpen className="w-4 h-4 text-white/70 group-hover:text-white/90 transition-colors drop-shadow-sm" />
              </button>
            </div>
          )}
        </div>
      </div>

      {/* Photo Story Point - pulsing dot */}
      {(() => {
        const storyText = getLocalizedText("photo_story") || t("home.hero.photoStoryContent");
        if (!storyText) return null;
        return (
          <button
            onClick={() => onPhotoStory?.(storyText, template.id)}
            className="absolute bottom-24 left-8 z-20 group flex items-center gap-2 cursor-pointer"
            aria-label={t("home.hero.photoStory")}
          >
            <span className="relative flex h-4 w-4">
              <span className="animate-ping absolute inline-flex h-full w-full rounded-full bg-white/70 opacity-75" />
              <span className="relative inline-flex rounded-full h-4 w-4 bg-white shadow-lg" />
            </span>
            <span className="text-xs text-white/80 opacity-0 group-hover:opacity-100 transition-opacity duration-300 drop-shadow-md whitespace-nowrap">
              {t("home.hero.photoStory")}
            </span>
          </button>
        );
      })()}
    </div>
  );
});
HeroSlide.displayName = "HeroSlide";

const PhotoStoryDialog = ({ content, onClose, templateId }: { content: string; onClose: () => void; templateId?: string }) => {
  const { t, i18n } = useTranslation();
  const iChingText = t("home.hero.photoStoryIChing", '《易经·井》：\u201C井养而不穷也。\u201D —— 一口井滋养着周围的人，从不枯竭。这个街角的拉面店正如一口古井，日复一日为邻里提供温暖与慰藉，维系着社区最朴素的纽带。');
  const { narrativeDisplay, iChingDisplay, translateStory, isTranslating, showTranslation } = useStoryTranslation(content, iChingText);
  const { counts, userReaction, toggleReaction } = useStoryReactions(templateId);
  const { user } = useAuth();
  const [showComments, setShowComments] = useState(false);
  const { data: storyComments } = useComments(templateId || "", "story", { enabled: !!templateId });
  const commentsCount = storyComments?.reduce((acc: number, c: any) => acc + 1 + (c.replies?.length || 0), 0) || 0;

  const handleShare = async () => {
    try {
      if (navigator.share) {
        await navigator.share({ title: t("home.hero.photoStory"), url: window.location.href });
      } else {
        await navigator.clipboard.writeText(window.location.href);
        toast.success(t("common.linkCopied", "链接已复制"));
      }
    } catch { /* cancelled */ }
  };

  return (
    <div className="fixed inset-0 z-50 flex items-center justify-center bg-black/60 backdrop-blur-sm" onClick={onClose}>
      <div 
        className="relative max-w-lg w-full mx-4 bg-background rounded-2xl shadow-2xl overflow-hidden animate-fade-in"
        onClick={(e) => e.stopPropagation()}
      >
        <div className="p-6 sm:p-8 space-y-4">
          <div className="flex items-center gap-3">
            <div className="w-10 h-10 rounded-full bg-primary/10 flex items-center justify-center">
              <Camera className="w-5 h-5 text-primary" />
            </div>
            <h3 className="text-lg font-bold text-foreground">{t("home.hero.photoStory")}</h3>
          </div>
          <p className="text-sm sm:text-base text-muted-foreground leading-relaxed">
            {narrativeDisplay || content}
          </p>
          <div className="pt-3 border-t border-border/50">
            <IChingSection text={iChingText} translatedText={iChingDisplay} />
          </div>
          {/* Like / Dislike / Share */}
          <div className="flex items-center justify-center gap-4 pt-2 border-t border-border/50">
            <button
              onClick={() => {
                if (!user) { toast.info(t("common.loginRequired", "请先登录")); return; }
                toggleReaction.mutate("like");
              }}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                userReaction === "like" ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
              }`}
            >
              <ThumbsUp className={`w-4 h-4 ${userReaction === "like" ? "fill-primary" : ""}`} />
              {counts.likes > 0 && <span>{counts.likes}</span>}
            </button>
            <button
              onClick={() => {
                if (!user) { toast.info(t("common.loginRequired", "请先登录")); return; }
                toggleReaction.mutate("dislike");
              }}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                userReaction === "dislike" ? "bg-destructive/15 text-destructive" : "text-muted-foreground hover:text-destructive hover:bg-destructive/10"
              }`}
            >
              <ThumbsDown className={`w-4 h-4 ${userReaction === "dislike" ? "fill-destructive" : ""}`} />
              {counts.dislikes > 0 && <span>{counts.dislikes}</span>}
            </button>
            <button
              onClick={handleShare}
              className="inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium text-muted-foreground hover:text-primary hover:bg-primary/10 transition-all duration-200 active:scale-95"
            >
              <Share2 className="w-4 h-4" />
            </button>
            <button
              onClick={() => setShowComments(!showComments)}
              className={`inline-flex items-center gap-1.5 px-3 py-1.5 rounded-full text-sm font-medium transition-all duration-200 active:scale-95 ${
                showComments ? "bg-primary/15 text-primary" : "text-muted-foreground hover:text-primary hover:bg-primary/10"
              }`}
            >
              <MessageSquare className="w-4 h-4" />
              {commentsCount > 0 && <span>{commentsCount}</span>}
            </button>
          </div>
          {/* Story Comments */}
          {showComments && templateId && (
            <div className="mt-2">
              <RestaurantComments targetId={templateId} targetType="story" />
            </div>
          )}
          <div className="flex items-center justify-between">
            <Button
              variant="outline"
              size="sm"
              className="gap-2 h-auto py-2 px-4 text-sm font-medium border-primary/30 text-primary hover:bg-primary/10 hover:border-primary/50 rounded-full transition-all duration-300"
              onClick={() => translateStory(i18n.language)}
              disabled={isTranslating}
            >
              {isTranslating ? (
                <><Loader2 className="h-3.5 w-3.5 animate-spin" /><span>{t("translate.translating", "翻译中...")}</span></>
              ) : showTranslation ? (
                <><RotateCcw className="h-3.5 w-3.5" /><span>{t("translate.showOriginal", "显示原文")}</span></>
              ) : (
                <><Languages className="h-3.5 w-3.5" /><span>{t("translate.button", "翻译")}</span></>
              )}
            </Button>
            <button 
              onClick={onClose}
              className="text-sm text-primary hover:text-primary/80 transition-colors"
            >
              {t("common.close", "关闭")}
            </button>
          </div>
        </div>
      </div>
    </div>
  );
};

const Home = () => {
  const { t, i18n } = useTranslation();
  const navigate = useNavigate();
  const queryClient = useQueryClient();
  const { settings: siteSettings } = useSiteSettings();
  const { data: templates, isLoading: isLoadingTemplates, refetch: refetchTemplates } = useActiveHomepageTemplates();
  const [currentIndex, setCurrentIndex] = useState(0);
  const [stats, setStats] = useState<{ order_count: number; reserve_count: number } | null>(null);
  const timerRef = useRef<NodeJS.Timeout | null>(null);
  const [firstSlideReady, setFirstSlideReady] = useState(false);
  const [askDialogOpen, setAskDialogOpen] = useState(false);
  const [photoStoryOpen, setPhotoStoryOpen] = useState(false);
  const [photoStoryContent, setPhotoStoryContent] = useState("");
  const [photoStoryTemplateId, setPhotoStoryTemplateId] = useState<string | undefined>(undefined);
  
  // Mobile/WebView detection for conditional layout
  const isMobile = useIsMobile();
  const { isWebView, isNativeApp } = useEnvironment();
  const showMobileLayout = isMobile || isWebView;
  
  // Use environment hook values instead of direct function calls to avoid exceptions
  const shouldHideAppDownload = isWebView || isNativeApp;
  
  // Check if AI assistant is enabled
  const isAIAssistantEnabled = siteSettings?.ai_assistant_enabled !== false;
  
  // Handler for when the first slide's content is ready
  const handleContentReady = useCallback(() => {
    setFirstSlideReady(true);
  }, []);

  // Track page view
  usePageView({ pageType: "home" });

  const fetchStats = useCallback(async () => {
    try {
      const response = await fetch("https://v.xiaoxiong.pt/api/get_info");
      const result = await response.json();
      if (result) {
        setStats({
          order_count: result.order_count || 0,
          reserve_count: result.reserve_count || 0
        });
      }
    } catch (error) {
      console.error("Failed to fetch stats:", error);
    }
  }, []);

  useEffect(() => {
    fetchStats();
  }, [fetchStats]);

  // Pull-to-refresh handler - clears all caches and forces fresh data
  const handleRefresh = useCallback(async () => {
    // Clear all related caches first
    queryClient.removeQueries({ queryKey: ['homepage-templates'] });
    queryClient.removeQueries({ queryKey: ['restaurants'] });
    queryClient.removeQueries({ queryKey: ['activities'] });
    queryClient.removeQueries({ queryKey: ['recent-activities'] });
    
    // Then refetch fresh data
    await Promise.all([
      refetchTemplates(),
      fetchStats(),
      queryClient.invalidateQueries({ queryKey: ['restaurants'] }),
      queryClient.invalidateQueries({ queryKey: ['activities'] }),
      queryClient.invalidateQueries({ queryKey: ['recent-activities'] }),
    ]);
  }, [refetchTemplates, fetchStats, queryClient]);

  // Auto-rotate carousel
  useEffect(() => {
    if (!templates || templates.length <= 1) return;

    const currentTemplate = templates[currentIndex];
    const duration = currentTemplate?.duration || 5000;

    timerRef.current = setTimeout(() => {
      setCurrentIndex((prev) => (prev + 1) % templates.length);
    }, duration);

    return () => {
      if (timerRef.current) clearTimeout(timerRef.current);
    };
  }, [templates, currentIndex]);

  const goToSlide = useCallback((index: number) => {
    if (timerRef.current) clearTimeout(timerRef.current);
    setCurrentIndex(index);
  }, []);

  const goToPrev = useCallback(() => {
    if (!templates) return;
    if (timerRef.current) clearTimeout(timerRef.current);
    setCurrentIndex((prev) => (prev - 1 + templates.length) % templates.length);
  }, [templates]);

  const goToNext = useCallback(() => {
    if (!templates) return;
    if (timerRef.current) clearTimeout(timerRef.current);
    setCurrentIndex((prev) => (prev + 1) % templates.length);
  }, [templates]);

  const currentLang = i18n.language;
  const showControls = templates && templates.length > 1;

  return (
    <PullToRefresh onRefresh={handleRefresh}>
      <div className="min-h-screen">
        {/* Hero Section - Conditional Layout */}
        {showMobileLayout ? (
          // Mobile/WebView: Simplified hero without background
          <MobileHeroSection 
            stats={stats} 
            onAskXiaoxiong={() => setAskDialogOpen(true)} 
          />
        ) : (
          // Desktop: Full carousel with background media
          <section className="relative h-screen flex items-start overflow-hidden bg-background">
            {/* 统计数据显示 - 左上角 */}
            {stats && <StatsDisplay stats={stats} t={t} />}

            {/* Carousel Slides */}
            <div className={cn(
              "absolute inset-0 w-full h-full transition-opacity duration-500",
              firstSlideReady ? "opacity-100" : "opacity-0"
            )}>
              {templates?.map((template, index) => (
                <HeroSlide
                  key={template.id}
                  template={template}
                  isActive={index === currentIndex}
                  currentLang={currentLang}
                  t={t}
                  onContentReady={index === 0 ? handleContentReady : undefined}
                  onAskXiaoxiong={() => setAskDialogOpen(true)}
                  onDIYCook={() => navigate("/ai-recipe")}
                  onPhotoStory={(storyText) => {
                    setPhotoStoryContent(storyText);
                    setPhotoStoryTemplateId(template.id);
                    setPhotoStoryOpen(true);
                  }}
                />
              ))}
            </div>

            {/* Loading state - show skeleton until content is actually ready */}
            <div 
              className={cn(
                "absolute inset-0 w-full h-full z-20 transition-opacity duration-500",
                (isLoadingTemplates || !firstSlideReady) ? "opacity-100" : "opacity-0 pointer-events-none"
              )}
            >
              <HomeSkeleton />
            </div>

            {/* Fallback if no templates (only after loading completes) */}
            {!isLoadingTemplates && (!templates || templates.length === 0) && (
              <div className="absolute inset-0 w-full h-full">
                <img 
                  src={sushiRamenMobile} 
                  alt="Background" 
                  fetchPriority="high"
                  loading="eager"
                  decoding="async"
                  className="absolute inset-0 w-full h-full object-cover object-center sm:hidden"
                />
                <img 
                  src={sushiRamenHero} 
                  alt="Background" 
                  fetchPriority="high"
                  loading="eager"
                  decoding="async"
                  className="absolute inset-0 w-full h-full object-cover object-center hidden sm:block"
                />
                <div className="absolute inset-0 w-full h-full bg-gradient-to-b from-black/30 via-black/25 to-black/40" />
                <div className="relative z-10 container mx-auto px-4 sm:px-6 flex items-center min-h-screen">
                  <div className="max-w-4xl mx-auto text-center space-y-4 sm:space-y-8 animate-fade-in w-full">
                    <h1 className="text-3xl sm:text-5xl md:text-7xl font-bold text-white leading-tight px-4 drop-shadow-[0_2px_8px_rgba(0,0,0,0.8)]">
                      {t("home.hero.title")}
                    </h1>
                    <p className="text-sm sm:text-xl md:text-2xl text-white/95 max-w-2xl mx-auto px-4 drop-shadow-[0_2px_6px_rgba(0,0,0,0.7)]">
                      {t("home.hero.description")}
                    </p>
                  </div>
                </div>
              </div>
            )}

            {/* Carousel Controls - Dot Indicators Only */}
            {showControls && (
              <div className="absolute bottom-8 left-1/2 -translate-x-1/2 z-30 flex gap-2">
                {templates.map((_, index) => (
                  <button
                    key={index}
                    onClick={() => goToSlide(index)}
                    className={cn(
                      "w-3 h-3 rounded-full transition-all duration-300",
                      index === currentIndex 
                        ? "bg-white w-8" 
                        : "bg-white/50 hover:bg-white/70"
                    )}
                    aria-label={`Go to slide ${index + 1}`}
                  />
                ))}
              </div>
            )}
          </section>
        )}

      {/* Recent Activities Section */}
      <RecentActivitiesSection />

      {/* Recent Posts Section */}
      <RecentPostsSection />

      {/* Map Section */}
      <section className="py-12 sm:py-20 px-4 bg-secondary/20">
        <div className="container mx-auto max-w-7xl">
          <Suspense fallback={<div className="h-[400px] bg-muted/30 rounded-lg animate-pulse" />}>
            <HomeMapSection />
          </Suspense>
        </div>
      </section>

      {/* App Download Section - Hidden in WebView/Native App */}
      {!shouldHideAppDownload && (
      <section className="py-16 sm:py-24 px-4 relative overflow-hidden">
        {/* Background with soft edges using mask */}
        <div 
          className="absolute inset-0 bg-gradient-to-br from-primary/5 via-primary/3 to-primary/8"
          style={{
            maskImage: 'radial-gradient(ellipse 80% 70% at 50% 50%, black 40%, transparent 100%)',
            WebkitMaskImage: 'radial-gradient(ellipse 80% 70% at 50% 50%, black 40%, transparent 100%)',
          }}
        />
        
        {/* Decorative elements */}
        <div className="absolute top-1/4 left-1/4 w-72 h-72 bg-primary/8 rounded-full blur-3xl" />
        <div className="absolute bottom-1/4 right-1/4 w-96 h-96 bg-primary/5 rounded-full blur-3xl" />
        
        <div className="container mx-auto max-w-5xl relative z-10">
          <div className="flex flex-col items-center justify-center gap-8">
            
            {/* Content */}
            <div className="text-center max-w-md">
              <div className="inline-flex items-center gap-2 bg-primary/10 text-primary text-sm font-medium px-4 py-2 rounded-full mb-4">
                <Smartphone className="w-4 h-4" />
                <span>Mobile App</span>
              </div>
              <h3 className="text-2xl sm:text-3xl md:text-4xl font-bold text-foreground mb-4">
                {t("home.app.title")}
              </h3>
              <p className="text-base sm:text-lg text-muted-foreground mb-8 leading-relaxed">
                {t("home.app.description")}
              </p>
              <div className="flex flex-col items-center gap-4">
                <div className="flex flex-col sm:flex-row items-center justify-center gap-4">
                  {/* App Store */}
                  <a 
                    href="https://apps.apple.com/cn/app/xiaoxiong/id6755481369" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="relative group"
                  >
                    <div className="absolute -inset-2 bg-gradient-to-r from-primary via-primary-glow to-primary rounded-2xl blur-lg opacity-40 group-hover:opacity-70 transition-opacity" />
                    <div className="relative bg-black hover:bg-gray-900 h-[52px] sm:h-[56px] w-[160px] sm:w-[180px] rounded-xl transition-all hover:scale-105 shadow-2xl hover:shadow-primary/30 border border-white/10 flex items-center justify-center">
                      <img 
                        src={appStoreBadge} 
                        alt="Download on the App Store" 
                        width={108}
                        height={36}
                        className="h-8 sm:h-9"
                      />
                    </div>
                  </a>
                  
                  {/* Google Play */}
                  <a 
                    href="https://play.google.com/store/apps/details?id=com.xiaoxiong.market" 
                    target="_blank" 
                    rel="noopener noreferrer"
                    className="relative group"
                  >
                    <div className="absolute -inset-2 bg-gradient-to-r from-primary via-primary-glow to-primary rounded-2xl blur-lg opacity-40 group-hover:opacity-70 transition-opacity" />
                    <div className="relative bg-black hover:bg-gray-900 h-[52px] sm:h-[56px] w-[160px] sm:w-[180px] rounded-xl transition-all hover:scale-105 shadow-2xl hover:shadow-primary/30 border border-white/10 flex items-center justify-center">
                      <img 
                        src={googlePlayBadge} 
                        alt="Get it on Google Play" 
                        width={145}
                        height={56}
                        className="h-12 sm:h-14"
                      />
                    </div>
                  </a>
                </div>
                
                {/* Download hint */}
                <div className="flex items-center gap-2 text-sm text-muted-foreground">
                  <Download className="w-4 h-4 animate-bounce" />
                  <span>{t("home.app.downloadNow")}</span>
                </div>
              </div>
            </div>
          </div>
        </div>
      </section>
      )}

      {/* CTA Section */}
      <section className="py-16 sm:py-20 px-4 bg-gradient-to-r from-primary/90 to-primary relative overflow-hidden rounded-3xl mx-4 sm:mx-8 lg:mx-16 mb-8">
        <div className="absolute inset-0 bg-grid-pattern opacity-10" />
        <div className="absolute top-0 right-0 w-64 sm:w-96 h-64 sm:h-96 bg-white/10 rounded-full blur-3xl" />
        <div className="absolute bottom-0 left-0 w-64 sm:w-96 h-64 sm:h-96 bg-white/10 rounded-full blur-3xl" />
        
        <div className="container mx-auto max-w-4xl text-center relative z-10">
          <h2 className="text-3xl sm:text-4xl md:text-5xl font-bold text-primary-foreground mb-4 sm:mb-6 px-4">
            {t("home.cta.title")}
          </h2>
          <p className="text-base sm:text-xl text-primary-foreground/90 mb-6 sm:mb-8 max-w-2xl mx-auto px-4"
            dangerouslySetInnerHTML={{
              __html: t("home.cta.description")
                .replace(/(免费|for free|gratuitamente|gratis|gratuitement|kostenlos|無料で|무료로|مجاناً|бесплатно|gratuitamente)/gi, 
                  '<span class="font-bold text-xl sm:text-3xl">$1</span>')
            }}
          />
          
          <div className="flex justify-center">
            <Button size="lg" variant="secondary" asChild className="text-base sm:text-lg shadow-xl hover:shadow-2xl">
              <Link to="/join-us">
                <Store className="mr-2 w-4 sm:w-5 h-4 sm:h-5" />
                {t("home.cta.button")}
              </Link>
            </Button>
          </div>
        </div>
      </section>

      {/* Ask Xiaoxiong Dialog - conditionally rendered based on settings */}
      {isAIAssistantEnabled && (
        <AskXiaoxiongDialog open={askDialogOpen} onOpenChange={setAskDialogOpen} />
      )}

      {/* Photo Story Dialog */}
      {photoStoryOpen && (
        <PhotoStoryDialog 
          content={photoStoryContent} 
          onClose={() => setPhotoStoryOpen(false)}
          templateId={photoStoryTemplateId}
        />
      )}
      </div>
    </PullToRefresh>
  );
};

export default Home;
